            type: 'mcq',
            title: 'Airborne Infection Isolation Room',
            desc: 'An AIIR for TB requires:',
            choices: [
                { text: 'Negative pressure with 6-12 air changes per hour exhausted outside or through HEPA', correct: true, log: 'Correct. Rationale: CDC TB isolation specifications: negative pressure, 6-12 ACH, HEPA filtration.' },
                { text: 'Positive pressure with HEPA', log: 'Incorrect. Positive pressure is for immunocompromised protection, not source isolation.' },
                { text: 'Standard room with door closed', log: 'Incorrect. Insufficient — engineering controls are required.' },
                { text: '2 air changes per hour', log: 'Incorrect. Below minimum required ventilation for AIIR.' },
            ],
